const dropdownButtons=document.querySelectorAll(".button--dropdown");dropdownButtons.length>0&&dropdownButtons.forEach(e=>{e.addEventListener("click",function(){this.classList.toggle("is-open")})});const dropdownFields=document.querySelectorAll(".field-dropdown");function closeAllSelects(e=null){dropdownFields.forEach(s=>{s!==e&&s.classList.remove("is-open")})}dropdownFields.length>0&&dropdownFields.forEach(e=>{e.querySelector("input").readOnly=!0,e.addEventListener("click",s=>{s.stopPropagation(),closeAllSelects(e),e.classList.toggle("is-open")})}),document.addEventListener("click",()=>{closeAllSelects()});const burger=document.querySelector(".mobile-burger");burger&&burger.addEventListener("click",()=>{burger.classList.toggle("is-active")});const specialOffersSlider=new Swiper(".special-offers__slider",{slidesPerView:1.15,spaceBetween:8,navigation:{nextEl:".special-offers__next",prevEl:".special-offers__prev"},breakpoints:{480:{spaceBetween:12},768:{slidesPerView:3}}}),companiesSlider=new Swiper(".companies__slider",{slidesPerView:4,spaceBetween:9,breakpoints:{480:{spaceBetween:12},560:{slidesPerView:5},700:{slidesPerView:6},1440:{slidesPerView:8}}});